def remove_writer(self, fd):
    readable = fd in self.readers
    on_read = self.readers.get(fd)
    try:
        self._remove_from_loop(fd)
    finally:
        if readable:
            cb, args = on_read
            self.add(fd, cb, READ | ERR, args)

